import React from 'react';

/**
 * Affiche les étapes d'un calcul pas à pas.
 * steps : [{ current_state, symbol, next_state }]
 */
export default function StepByStep({ steps = [], accepted, message, finalState }) {
  if (!steps.length && accepted === undefined) return null;

  return (
    <div style={{ fontFamily: 'Space Mono, monospace', fontSize: 12 }}>
      {/* Résultat global */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 10,
        padding: '10px 14px',
        borderRadius: 6,
        marginBottom: 14,
        background: accepted
          ? 'rgba(16,185,129,0.1)'
          : 'rgba(239,68,68,0.1)',
        border: `1px solid ${accepted ? 'rgba(16,185,129,0.3)' : 'rgba(239,68,68,0.3)'}`,
      }}>
        <span style={{ fontSize: 18 }}>{accepted ? '✓' : '✗'}</span>
        <div>
          <div style={{
            fontWeight: 700,
            color: accepted ? '#10b981' : '#ef4444',
            fontSize: 13,
          }}>
            {message}
          </div>
          {finalState && (
            <div style={{ color: '#475569', fontSize: 11, marginTop: 2 }}>
              État final atteint : <span style={{ color: '#94a3b8' }}>{finalState}</span>
            </div>
          )}
        </div>
      </div>

      {/* Étapes */}
      {steps.length > 0 && (
        <div>
          <div style={{
            fontSize: 10, letterSpacing: '0.08em', textTransform: 'uppercase',
            color: '#475569', marginBottom: 8,
          }}>
            Trace d'exécution ({steps.length} étape{steps.length > 1 ? 's' : ''})
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {steps.map((step, i) => (
              <div key={i} style={{
                display: 'flex', alignItems: 'center', gap: 8,
                padding: '6px 10px',
                background: '#13161e',
                borderRadius: 4,
                border: '1px solid #1a1e28',
                animation: `fadeIn 0.2s ease ${i * 0.04}s both`,
              }}>
                <span style={{ color: '#475569', minWidth: 20, textAlign: 'right' }}>
                  {i + 1}.
                </span>
                <span style={{
                  color: '#7c3aed', minWidth: 60,
                  background: 'rgba(124,58,237,0.1)',
                  padding: '1px 6px', borderRadius: 3,
                }}>
                  {step.current_state}
                </span>
                <span style={{ color: '#475569' }}>──</span>
                <span style={{
                  color: '#f59e0b', minWidth: 20, textAlign: 'center',
                  background: 'rgba(245,158,11,0.1)',
                  padding: '1px 6px', borderRadius: 3,
                }}>
                  {step.symbol}
                </span>
                <span style={{ color: '#475569' }}>──▶</span>
                <span style={{
                  color: step.next_state ? '#00e5ff' : '#ef4444',
                  background: step.next_state
                    ? 'rgba(0,229,255,0.1)'
                    : 'rgba(239,68,68,0.1)',
                  padding: '1px 6px', borderRadius: 3,
                }}>
                  {step.next_state ?? '∅'}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
